import { useMemo } from 'react'
import { Bar, BarChart, CartesianGrid, Tooltip, XAxis, YAxis } from 'recharts'
import { formatMs } from '@/lib/observability-format'
import type { SessionMetrics } from '@/lib/observability-types'
import { usePerformance } from '@/lib/observability-hooks'
import { ChartCard, ChartTooltipShell } from '@/components/observability-chart-shared'

interface ChartEntry {
  turn: number
  user?: number
  agent?: number
}

const TalkTimeTooltip = ({
  active,
  payload,
  label,
}: {
  active?: boolean
  payload?: Array<{ name: string; value: number; color: string }>
  label?: number
}) => {
  return (
    <ChartTooltipShell
      active={active}
      label={label}
      rows={payload?.length ? payload.map((p) => ({ label: p.name, value: formatMs(p.value) })) : []}
    />
  )
}

export const TalkTimeChart = ({ metrics: metricsProp }: { metrics?: SessionMetrics | null }) => {
  const { metrics: hookMetrics } = usePerformance()
  const metrics = metricsProp ?? hookMetrics

  const chartData = useMemo<ChartEntry[]>(() => {
    if (!metrics?.turns?.length) return []
    return metrics.turns
      .filter((t) => t.stt_audio_duration_ms != null || t.tts_audio_duration_ms != null)
      .map((t) => ({
        turn: t.turn_number,
        user: t.stt_audio_duration_ms,
        agent: t.tts_audio_duration_ms,
      }))
  }, [metrics])

  if (!chartData.length) return null

  return (
    <ChartCard
      title="Talk Time"
      subtitle="User vs agent speaking duration per turn"
      legend={[
        { color: 'var(--info)', label: 'User' },
        { color: 'var(--success)', label: 'Agent' },
      ]}
    >
      <BarChart data={chartData} barCategoryGap="20%">
        <CartesianGrid strokeDasharray="3 3" stroke="var(--st1)" />
        <XAxis
          dataKey="turn"
          tick={{ fill: 'var(--muted-foreground)', fontSize: 12 }}
          stroke="var(--st2)"
        />
        <YAxis
          tickFormatter={(v: number) => formatMs(v)}
          tick={{ fill: 'var(--muted-foreground)', fontSize: 12 }}
          stroke="var(--st2)"
        />
        <Tooltip content={<TalkTimeTooltip />} cursor={{ fill: 'color-mix(in oklab, var(--muted) 40%, transparent)' }} />
        <Bar dataKey="user" name="User" stackId="a" fill="var(--info)" radius={[0, 0, 0, 0]} />
        <Bar dataKey="agent" name="Agent" stackId="a" fill="var(--success)" radius={[4, 4, 0, 0]} />
      </BarChart>
    </ChartCard>
  )
}
